import type { ElementType } from 'react';

interface PageHeaderProps {
  title: string;
  description?: string;
  action?: { label: string; onClick: () => void; icon?: ElementType };
}

export default function PageHeader({ title, description, action }: PageHeaderProps) {
  const Icon = action?.icon;
  return (
    <div className="flex items-center justify-between pb-6 mb-6 border-b border-[var(--border-subtle)]">
      <div>
        <h1 className="text-xl font-semibold text-[var(--text-primary)] tracking-tight">{title}</h1>
        {description && <p className="text-[13px] text-[var(--text-tertiary)] mt-0.5">{description}</p>}
      </div>
      {action && (
        <button
          onClick={action.onClick}
          className="inline-flex items-center gap-2 bg-[var(--accent)] text-white rounded-lg px-4 py-2 text-[13px] font-medium hover:bg-[var(--accent-hover)] transition-all duration-150 press-effect"
        >
          {Icon && <Icon className="w-4 h-4" />}
          {action.label}
        </button>
      )}
    </div>
  );
}
```

Note: PageHeader needs `'use client'` because `action.onClick` is an event handler. Add it.

