'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  LayoutDashboard, Gift, Award, Users,
  QrCode, ScanLine, Megaphone, BarChart3,
  CreditCard, Settings, Menu, X,
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface NavItem {
  label: string;
  href: string;
  icon: React.ElementType;
}

interface NavGroup {
  title: string;
  items: NavItem[];
}

const NAV: NavGroup[] = [
  {
    title: 'Principal',
    items: [
      { label: 'Tableau de bord', href: '/merchant', icon: LayoutDashboard },
      { label: 'Programmes', href: '/merchant/programs', icon: Gift },
      { label: 'Récompenses', href: '/merchant/rewards', icon: Award },
      { label: 'Clients', href: '/merchant/clients', icon: Users },
    ],
  },
  {
    title: 'Outils',
    items: [
      { label: 'QR Codes', href: '/merchant/qr-codes', icon: QrCode },
      { label: 'Scanner', href: '/merchant/scanner', icon: ScanLine },
      { label: 'Campagnes', href: '/merchant/campaigns', icon: Megaphone },
      { label: 'Analytiques', href: '/merchant/analytics', icon: BarChart3 },
    ],
  },
  {
    title: 'Gestion',
    items: [
      { label: 'Abonnement', href: '/merchant/subscription', icon: CreditCard },
      { label: 'Paramètres', href: '/merchant/settings', icon: Settings },
    ],
  },
];

export default function Sidebar() {
  const pathname = usePathname();
  const [mobileOpen, setMobileOpen] = useState(false);

  const isActive = (href: string) => {
    if (href === '/merchant') return pathname === '/merchant';
    return pathname.startsWith(href);
  };

  const renderNav = (onClose?: () => void) => (
    <nav className="flex-1 overflow-y-auto py-3 px-2">
      {NAV.map(group => (
        <div key={group.title} className="mb-4">
          <p className="text-[11px] font-semibold uppercase text-[var(--text-tertiary)] px-3 mb-1.5 tracking-wider">
            {group.title}
          </p>
          {group.items.map(item => {
            const Icon = item.icon;
            const active = isActive(item.href);
            return (
              <Link
                key={item.href}
                href={item.href}
                onClick={onClose}
                className={cn(
                  'group flex items-center gap-2.5 w-full px-3 py-[7px] rounded-lg text-[13px] leading-none transition-all duration-150 relative',
                  active
                    ? 'text-[var(--text-primary)] bg-[var(--accent-subtle)] font-medium'
                    : 'text-[var(--text-secondary)] hover:text-[var(--text-primary)] hover:bg-[var(--glass-active)]',
                )}
              >
                {active && (
                  <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[3px] h-4 bg-[var(--accent)] rounded-r-full" />
                )}
                <Icon className={cn(
                  'w-4 h-4 flex-shrink-0',
                  active ? 'text-[var(--accent)]' : 'text-[var(--text-tertiary)] group-hover:text-[var(--text-secondary)]',
                )} />
                <span className="truncate">{item.label}</span>
              </Link>
            );
          })}
        </div>
      ))}
    </nav>
  );

  return (
    <>
      {/* Desktop sidebar */}
      <aside className="hidden md:flex flex-col shrink-0 w-56 bg-[var(--bg-sidebar)] border-r border-[var(--border-default)] overflow-hidden">
        {renderNav()}
      </aside>

      {/* Mobile toggle */}
      <button
        onClick={() => setMobileOpen(!mobileOpen)}
        className="md:hidden fixed top-2 left-2 z-[60] p-2 rounded-lg bg-[var(--bg-elevated)] text-[var(--text-secondary)] hover:text-[var(--text-primary)]"
      >
        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
      </button>

      {/* Mobile overlay */}
      {mobileOpen && (
        <>
          <div className="md:hidden fixed inset-0 z-[55] bg-black/40 backdrop-blur-sm" onClick={() => setMobileOpen(false)} />
          <aside className="md:hidden flex flex-col fixed top-0 left-0 bottom-0 w-72 z-[56] bg-[var(--bg-sidebar)] border-r border-[var(--border-default)]">
            <div className="px-5 h-12 flex items-center border-b border-[var(--border-default)] shrink-0">
              <span className="text-[var(--text-primary)] font-bold text-[15px] tracking-tight">Royall</span>
              <span className="text-[var(--accent)] font-bold text-[15px]">Azz</span>
            </div>
            {renderNav(() => setMobileOpen(false))}
          </aside>
        </>
      )}
    </>
  );
}

import Header from '@/components/layout/Header';
import Sidebar from '@/components/layout/Sidebar';

export default function MerchantLayout({ children }: { children: React.ReactNode }) {
  return (
    <div className="h-screen flex flex-col">
      <Header />
      <div className="flex flex-1 overflow-hidden">
        <Sidebar />
        <main className="flex-1 overflow-y-auto p-6 md:p-8">
          <div className="max-w-6xl mx-auto page-enter">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
}

import PageHeader from '@/components/layout/PageHeader';

export default function MerchantHome() {
  return (
    <div className="space-y-6">
      <PageHeader title="Tableau de bord" description="Vue d'ensemble de votre activité fidélité." />
      <p className="text-[var(--text-secondary)]">Dashboard à venir...</p>
    </div>
  );
}

